ret -= (GetBlur2(uv_y2)-GetBlur1(uv_y2));
ret += 1.2*GetPixel(uv_y2)+.15*GetBlur1(uv_y2);
ret += 1;
ret = lum(ret);
ret -= .2*lum(tex3d(sampler_noisevol_lq,vec3(vUv*1.5,0.1*uTime)));
ret = mix(ret,.75*ret*lum(.6*GetBlur3(uv_y)-.7*GetPixel(vUv)-.3*GetBlur1(uv_y2)),pow(hue_shader,ret));
ret *= .8;
ret *= ret;
ret = sqrt(ret);


